/**
 * Admin booking — внутренняя «бронь» для менеджера.
 * Шаги: лид (новый или существующий) → выбор свободного слота → подтверждение.
 */

import { useEffect, useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { fetchAllSlots, patchSlot, type SlotDto } from '../api/schedule'
import { fetchLeads, createLead, updateLead, moveLeadStage, type LeadDto } from '../api/crm'

type Step = 'lead' | 'slot' | 'done'
type Track = 'python' | 'scratch' | 'vibe' | ''

const TRACKS: { value: Track; label: string }[] = [
  { value: '',        label: 'Любой' },
  { value: 'python',  label: '🐍 Python' },
  { value: 'scratch', label: '🎮 Scratch' },
  { value: 'vibe',    label: '🌐 Vibe-coding' },
]

export default function AdminBooking() {
  const navigate = useNavigate()
  const { toast, show } = useToast()

  const [step, setStep] = useState<Step>('lead')

  // Lead
  const [leads, setLeads] = useState<LeadDto[]>([])
  const [leadMode, setLeadMode] = useState<'new' | 'existing'>('new')
  const [selectedLeadId, setSelectedLeadId] = useState<string>('')
  const [parentName, setParentName] = useState('')
  const [parentPhone, setParentPhone] = useState('')
  const [parentEmail, setParentEmail] = useState('')
  const [childName, setChildName] = useState('')
  const [childAge, setChildAge] = useState<number>(10)
  const [track, setTrack] = useState<Track>('python')
  const [notes, setNotes] = useState('')
  const [creatingLead, setCreatingLead] = useState(false)

  // Slot
  const [slots, setSlots] = useState<SlotDto[]>([])
  const [slotsLoading, setSlotsLoading] = useState(false)
  const [bookingSlotId, setBookingSlotId] = useState<string | null>(null)
  const [bookedSlot, setBookedSlot] = useState<SlotDto | null>(null)
  const [bookedLead, setBookedLead] = useState<LeadDto | null>(null)

  useEffect(() => {
    fetchLeads({ stage: 'new' }).then(setLeads).catch(() => {/* ignore */})
  }, [])

  useEffect(() => {
    if (step !== 'slot') return
    setSlotsLoading(true)
    const now = new Date()
    const in14 = new Date(now.getTime() + 14 * 86400000)
    fetchAllSlots(now.toISOString(), in14.toISOString())
      .then((all) => setSlots(all.filter((s) => s.status === 'scheduled' && !s.studentId)))
      .catch(() => show('Ошибка загрузки слотов', 'error'))
      .finally(() => setSlotsLoading(false))
  }, [step, show])

  const slotsByDay = useMemo(() => {
    const m = new Map<string, SlotDto[]>()
    for (const s of slots) {
      const d = new Date(s.datetime).toISOString().slice(0, 10)
      const arr = m.get(d) ?? []
      arr.push(s)
      m.set(d, arr)
    }
    return Array.from(m.entries()).sort(([a], [b]) => a.localeCompare(b))
  }, [slots])

  async function handleNextFromLead() {
    if (leadMode === 'existing') {
      if (!selectedLeadId) { show('Выбери лида', 'error'); return }
      setStep('slot')
      return
    }
    if (!parentName.trim() || !parentPhone.trim()) {
      show('Имя и телефон родителя обязательны', 'error'); return
    }
    setCreatingLead(true)
    try {
      const lead = await createLead({
        source: 'manual',
        parentName: parentName.trim(),
        parentPhone: parentPhone.trim(),
        parentEmail: parentEmail.trim() || undefined,
        childName: childName.trim() || undefined,
        childAge: childAge || undefined,
        track: track || undefined,
        notes: notes.trim() || undefined,
      })
      setSelectedLeadId(lead.id)
      show('Лид создан', 'success')
      setStep('slot')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setCreatingLead(false)
    }
  }

  async function handleBookSlot(slot: SlotDto) {
    setBookingSlotId(slot.id)
    try {
      // Привязываем слот к лиду (slotId), и переводим в trial_scheduled.
      const lead = await updateLead(selectedLeadId, {})
      // Note: updateLead doesn't take slotId in payload — use moveLeadStage which has slotId in patch later, but for now mark stage.
      await moveLeadStage(selectedLeadId, 'trial_scheduled')
      // Mark slot as 'trial'
      await patchSlot(slot.id, { type: 'trial', notes: `Лид: ${lead.parentName ?? lead.id.slice(0,8)}` })
      setBookedSlot(slot)
      setBookedLead(lead)
      setStep('done')
      show('Слот забронирован, лид → trial_scheduled', 'success')
    } catch (e) {
      show('Ошибка бронирования: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setBookingSlotId(null)
    }
  }

  function reset() {
    setStep('lead')
    setSelectedLeadId('')
    setParentName(''); setParentPhone(''); setParentEmail('')
    setChildName(''); setChildAge(10); setTrack('python'); setNotes('')
    setBookedSlot(null); setBookedLead(null)
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>📅</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Бронирование (внутреннее)</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Записать ученика на пробный</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 800, margin: '0 auto', padding: '28px 16px', display: 'flex', flexDirection: 'column', gap: 20 }}>

        {/* Шаги */}
        <div style={{ display: 'flex', gap: 8 }}>
          {(['lead', 'slot', 'done'] as Step[]).map((s, i) => (
            <div key={s} style={{
              flex: 1, padding: '8px 12px', borderRadius: 8, fontSize: 13, fontWeight: 700, textAlign: 'center',
              background: step === s ? 'var(--violet, #6b5ce7)' : 'var(--paper-2, #f9f8ff)',
              color: step === s ? '#fff' : 'var(--ink-soft)',
            }}>
              {i + 1}. {s === 'lead' ? 'Лид' : s === 'slot' ? 'Слот' : 'Готово'}
            </div>
          ))}
        </div>

        {/* Step 1 */}
        {step === 'lead' && (
          <div className="kb-card" style={{ padding: 24, display: 'flex', flexDirection: 'column', gap: 14 }}>
            <h2 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>Шаг 1. Кого записываем</h2>

            <div style={{ display: 'flex', gap: 8 }}>
              <button className="kb-btn" style={{ background: leadMode === 'new' ? 'var(--violet)' : 'transparent', color: leadMode === 'new' ? '#fff' : 'var(--ink)' }} onClick={() => setLeadMode('new')}>+ Новый лид</button>
              <button className="kb-btn" style={{ background: leadMode === 'existing' ? 'var(--violet)' : 'transparent', color: leadMode === 'existing' ? '#fff' : 'var(--ink)' }} onClick={() => setLeadMode('existing')}>Существующий ({leads.length})</button>
            </div>

            {leadMode === 'existing' ? (
              <div style={{ maxHeight: 300, overflowY: 'auto', border: '1px solid var(--paper-3)', borderRadius: 8 }}>
                {leads.length === 0 ? (
                  <div style={{ padding: 16, color: 'var(--ink-soft)', fontSize: 13 }}>Лидов в стадии «Новый» нет</div>
                ) : leads.map((l) => (
                  <label key={l.id} style={{ display: 'flex', gap: 10, padding: 10, cursor: 'pointer', borderBottom: '1px solid var(--paper-3)', background: selectedLeadId === l.id ? 'var(--paper-2)' : '#fff' }}>
                    <input type="radio" name="lead" checked={selectedLeadId === l.id} onChange={() => setSelectedLeadId(l.id)} />
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 700, fontSize: 14 }}>{l.parentName ?? '— без имени —'}</div>
                      <div style={{ fontSize: 12, color: 'var(--ink-soft)' }}>{l.parentPhone} · {l.childName} · {l.track}</div>
                    </div>
                  </label>
                ))}
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                <div><label style={lblStyle}>Имя родителя *</label><input style={inpStyle} value={parentName} onChange={(e) => setParentName(e.target.value)} /></div>
                <div><label style={lblStyle}>Телефон *</label><input style={inpStyle} value={parentPhone} onChange={(e) => setParentPhone(e.target.value)} placeholder="+7..." /></div>
                <div><label style={lblStyle}>Email</label><input style={inpStyle} type="email" value={parentEmail} onChange={(e) => setParentEmail(e.target.value)} /></div>
                <div><label style={lblStyle}>Имя ребёнка</label><input style={inpStyle} value={childName} onChange={(e) => setChildName(e.target.value)} /></div>
                <div><label style={lblStyle}>Возраст</label><input style={inpStyle} type="number" min={5} max={18} value={childAge} onChange={(e) => setChildAge(Number(e.target.value))} /></div>
                <div><label style={lblStyle}>Трек</label>
                  <select style={inpStyle} value={track} onChange={(e) => setTrack(e.target.value as Track)}>
                    {TRACKS.filter(t => t.value).map(t => <option key={t.value} value={t.value}>{t.label}</option>)}
                  </select>
                </div>
                <div style={{ gridColumn: '1 / -1' }}><label style={lblStyle}>Заметки</label><textarea style={{ ...inpStyle, minHeight: 60 }} value={notes} onChange={(e) => setNotes(e.target.value)} /></div>
              </div>
            )}

            <button className="kb-btn" style={{ background: 'var(--violet)', color: '#fff', alignSelf: 'flex-end' }} onClick={() => void handleNextFromLead()} disabled={creatingLead}>
              {creatingLead ? '...' : 'Дальше →'}
            </button>
          </div>
        )}

        {/* Step 2 */}
        {step === 'slot' && (
          <div className="kb-card" style={{ padding: 24, display: 'flex', flexDirection: 'column', gap: 14 }}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <h2 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>Шаг 2. Свободные слоты на 14 дней</h2>
              <button className="kb-btn" onClick={() => setStep('lead')}>← Назад</button>
            </div>

            {slotsLoading ? (
              <div style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
            ) : slotsByDay.length === 0 ? (
              <div style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>
                Свободных слотов нет. Сгенерь их в календаре, или создай вручную.
              </div>
            ) : slotsByDay.map(([date, dSlots]) => (
              <div key={date}>
                <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--ink-soft)', marginBottom: 6 }}>
                  {new Date(date).toLocaleDateString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long' })}
                </div>
                <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                  {dSlots.map((s) => {
                    const time = new Date(s.datetime).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })
                    return (
                      <button key={s.id}
                        onClick={() => void handleBookSlot(s)}
                        disabled={bookingSlotId === s.id}
                        style={{ padding: '6px 12px', border: '1.5px solid var(--violet)', background: '#fff', color: 'var(--violet)', borderRadius: 8, cursor: 'pointer', fontWeight: 700, fontSize: 13 }}>
                        {time} · {s.durationMin}мин · <code style={{ fontSize: 11 }}>{s.teacherId.slice(0,6)}</code>
                      </button>
                    )
                  })}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Step 3 */}
        {step === 'done' && bookedSlot && bookedLead && (
          <div className="kb-card" style={{ padding: 32, textAlign: 'center', background: 'var(--mint-soft, #d1fae5)' }}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>✅</div>
            <h2 style={{ margin: '0 0 12px', fontSize: 22, fontWeight: 900 }}>Записано</h2>
            <div style={{ fontSize: 14, marginBottom: 20 }}>
              <div><b>{bookedLead.parentName}</b> ({bookedLead.parentPhone})</div>
              <div>Ребёнок: {bookedLead.childName ?? '—'}, {bookedLead.childAge ?? '?'} лет, трек {bookedLead.track}</div>
              <div style={{ marginTop: 8 }}>
                {new Date(bookedSlot.datetime).toLocaleString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
            <div style={{ display: 'flex', gap: 8, justifyContent: 'center' }}>
              <button className="kb-btn" onClick={reset}>+ Записать ещё</button>
              <button className="kb-btn" style={{ background: 'var(--violet)', color: '#fff' }} onClick={() => navigate('/admin/crm')}>→ В CRM-воронку</button>
            </div>
          </div>
        )}
      </div>
    </PlatformShell>
  )
}

const lblStyle: React.CSSProperties = { display: 'block', fontSize: 12, fontWeight: 600, color: 'var(--ink-soft)', marginBottom: 4 }
const inpStyle: React.CSSProperties = { width: '100%', padding: '8px 12px', borderRadius: 8, border: '1px solid var(--paper-3)', fontSize: 14, fontFamily: 'inherit', boxSizing: 'border-box' }
